// ============================================
// Validate payload and build Anthropic request
// ============================================
// Expected input body:
// {
//   slug: "estetica-madura",
//   label: "Clínica Estética — madura (150 msgs)",
//   description: "Fluxo estabelecido, mix agendado/ghosting/objeção/escalada",
//   count: 150,
//   profile: {
//     name: "Clínica Vida Plena",
//     specialties: [...],
//     pricing: {...},
//     hours: "...",
//     location: "..."
//   },
//   created_by?: "dev@easyscale.co"
// }

const body = $input.first().json.body || {};

const required = ['slug', 'label', 'profile'];
for (const field of required) {
  if (!body[field]) {
    throw new Error(`Missing required field: ${field}`);
  }
}

const slug = String(body.slug).trim();
if (!/^[a-z0-9-]+$/.test(slug)) {
  throw new Error(`Invalid slug '${slug}'. Use lowercase letters, numbers, hyphens only.`);
}

const count = Math.min(Math.max(parseInt(body.count) || 100, 10), 500);
const profile = body.profile;
const profileJson = JSON.stringify(profile, null, 2);

const systemPrompt = `Você é um gerador de conversas WhatsApp realistas entre pacientes e atendentes de clínicas de estética/medicina.

PERFIL DA CLÍNICA (use estes dados ao gerar):
${profileJson}

DISTRIBUIÇÃO DE OUTCOMES (proporcional ao total solicitado):
- agendado (40%): paciente confirma consulta/avaliação com data e hora
- ghosting (30%): paciente some sem responder — última mensagem É DO PACIENTE, atendente não recebe resposta
- objecao_ativa (20%): questiona preço, compara com concorrente, diz "vou pensar" ou "tá caro"
- escalada_humana (10%): quer falar com médico, com o financeiro ou pede orçamento formal

VARIAÇÃO DE ABERTURAS DO PACIENTE (distribuir uniformemente):
- Veio de anúncio no Instagram
- Veio de Reels ou Story
- Pergunta direta de preço
- Pedido de antes/depois
- Indicação de amiga
- Comparação com concorrente

VARIAÇÃO DE ABORDAGEM DA ATENDENTE (distribuir uniformemente entre conversas):
- Tipo A convite_avaliacao: convida para avaliação gratuita antes de falar preço
- Tipo B preco_direto: responde preço logo, menciona parcelamento/PIX e depois convida
- Tipo C antes_depois: menciona resultados/fotos primeiro e depois convida
- Tipo D rapport_primeiro: pergunta o que incomoda, cria conexão e depois convida

REGRAS DE REALISMO — OBRIGATÓRIAS:
- Datas em março ou abril de 2026
- Nomes de pacientes variados e brasileiros (femininos e masculinos)
- Cada conversa: mínimo 4, máximo 20 mensagens
- Conversas "agendado" DEVEM terminar com data e hora confirmada pela atendente
- Conversas "ghosting": última mensagem deve ser do paciente (fromMe=false)
- Quando atendente menciona preço, SEMPRE inclui parcelamento OU desconto PIX
- Linguagem informal, PT-BR real: abreviações (vc, tb, tô, né), erros leves ocasionais
- Mensagens curtas em rajadas (2-3 mensagens seguidas do mesmo remetente) são comuns

FORMATO DE SAÍDA — JSON ESTRITO:
Retorne APENAS um array JSON válido, sem markdown, sem comentários, sem texto antes/depois.
Cada elemento é uma mensagem individual na ordem cronológica:

[
  {
    "remoteJid": "5511988887777@s.whatsapp.net",
    "fromMe": false,
    "pushName": "Maria Silva",
    "body": "Oi, vi o anúncio do botox no insta",
    "messageType": "conversation",
    "timestamp": 1776800000
  },
  {
    "remoteJid": "5511988887777@s.whatsapp.net",
    "fromMe": true,
    "pushName": null,
    "body": "Oi Maria! Que ótimo que chegou até a gente...",
    "messageType": "conversation",
    "timestamp": 1776800120
  }
]

REGRAS DO FORMATO:
- remoteJid: sempre "{ddd+numero}@s.whatsapp.net" (contato individual, nunca grupo)
- Cada conversa distinta usa um remoteJid único
- fromMe=false = mensagem do paciente; fromMe=true = mensagem da atendente
- pushName: nome do paciente quando fromMe=false; null quando fromMe=true
- messageType: sempre "conversation" (texto simples)
- timestamp: unix seconds, progressão realista entre mensagens (segundos a horas)
- Entre conversas diferentes, timestamps podem saltar dias
- Todas as mensagens de todas as conversas vêm num único array achatado, agrupadas por conversa`;

const userPrompt = `Gere aproximadamente ${count} mensagens total, distribuídas entre múltiplas conversas independentes (cada conversa com remoteJid único). Respeite a distribuição de outcomes. Retorne APENAS o array JSON.`;

return [{
  json: {
    slug,
    label: String(body.label),
    description: body.description ? String(body.description) : null,
    profile,
    created_by: body.created_by ? String(body.created_by) : 'n8n-simulator',
    count,
    anthropicPayload: {
      model: 'claude-haiku-4-5-20251001',
      max_tokens: 16000,
      system: systemPrompt,
      messages: [{ role: 'user', content: userPrompt }]
    }
  }
}];

// ============================================
// Parse Anthropic response → messages array
// ============================================
// Also produces SQL-safe pre-escaped strings for the Postgres node.
// Pattern: single-quote escape for text literals ('' for '),
// then the query wraps them in single quotes directly.

const response = $input.first().json;
const meta = $('Build Anthropic Prompt').first().json;

if (!response.content || !Array.isArray(response.content) || response.content.length === 0) {
  throw new Error('Anthropic response missing content: ' + JSON.stringify(response).slice(0, 500));
}

const rawText = response.content[0].text || '';

// Strip markdown code fences if the model added them despite instructions
let jsonText = rawText.trim();
const fenceMatch = jsonText.match(/^```(?:json)?\s*([\s\S]*?)\s*```$/);
if (fenceMatch) {
  jsonText = fenceMatch[1].trim();
}

let messages;
try {
  messages = JSON.parse(jsonText);
} catch (err) {
  throw new Error(`Failed to parse Anthropic JSON: ${err.message}. Raw (first 500 chars): ${jsonText.slice(0, 500)}`);
}

if (!Array.isArray(messages)) {
  throw new Error('Parsed response is not an array');
}

if (messages.length < 4) {
  throw new Error(`Too few messages generated: ${messages.length} (min 4)`);
}

// Validate each message has required fields
const required = ['remoteJid', 'fromMe', 'body', 'messageType', 'timestamp'];
for (let i = 0; i < messages.length; i++) {
  const msg = messages[i];
  for (const field of required) {
    if (!(field in msg)) {
      throw new Error(`Message #${i} missing field '${field}': ${JSON.stringify(msg).slice(0, 200)}`);
    }
  }
}

// Helper: escape single quotes for Postgres string literals
const sqlEscape = (s) => String(s).replace(/'/g, "''");

const profileJson = JSON.stringify(meta.profile);
const messagesJson = JSON.stringify(messages);

return [{
  json: {
    slug: meta.slug,
    label: meta.label,
    description: meta.description,
    profile: meta.profile,
    messages,
    created_by: meta.created_by,
    message_count: messages.length,
    usage: response.usage || null,
    // SQL-escaped values for the Postgres node
    sql: {
      slug: sqlEscape(meta.slug),
      label: sqlEscape(meta.label),
      description: meta.description === null || meta.description === undefined ? null : sqlEscape(meta.description),
      profile: sqlEscape(profileJson),
      messages: sqlEscape(messagesJson),
      created_by: sqlEscape(meta.created_by)
    }
  }
}];
